// Constants
var TAU = 6.283;          // τ = 2π ≈ 6.283 ✅ (full circle in radians)
var PHI = 1.618;          // φ = golden ratio ≈ 1.618 ✅
var SQRT_HALF = 0.707;    // √(1/2) ≈ 0.707 ✅

// Physics configuration
var config = {
    attractionForce: 4000,       // repulsion constant (misleading name - see below)
    springCoeff: 0.004,          // spring stiffness coefficient
    amplification: 0.92,         // velocity damping factor (misleading - see below)
    centerGravity: 0.0003,       // centering force strength
    streamCount: 40,             // max particle count
    streamDecay: 0.04,           // particle drag/decay rate
    theta: 0.06                  // camera smoothing factor
};

// Nodes
var nodes = [
    { id: 'hub',      label: 'Hub',      r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: 'alpha',    label: 'Alpha',    r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: 'beta',     label: 'Beta',     r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: 'gamma',    label: 'Gamma',    r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: 'delta',    label: 'Delta',    r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: 'epsilon',  label: 'Epsilon',  r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// Springs (edges connecting nodes)
var springs = [
    { a: 'hub', b: 'alpha',   rest: 160, k: 0.006 },
    { a: 'hub', b: 'beta',    rest: 160, k: 0.005 },
    { a: 'hub', b: 'gamma',   rest: 170, k: 0.004 },
    { a: 'hub', b: 'delta',   rest: 170, k: 0.004 },
    { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
    { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
    { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
    { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

// Camera state
var camera = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// Particles
var particles = [];
var frameCount = 0;

// Find node by ID
function findNode(id) {
    for (var i = 0; i < nodes.length; i++) {
        if (nodes[i].id === id) return nodes[i];
    }
    return null;
}

// Physics simulation step
function simulate() {
    // Node-node repulsion (Coulomb-like)
    for (var i = 0; i < nodes.length; i++) {
        for (var j = i + 1; j < nodes.length; j++) {
            var dx = nodes[i].x - nodes[j].x;
            var dy = nodes[i].y - nodes[j].y;
            var dist = Math.sqrt(dx * dx + dy * dy) || 1;
            var force = config.attractionForce / (dist * dist);
            var fx = (dx / dist) * force;
            var fy = (dy / dist) * force;
            nodes[i].vx += fx;
            nodes[i].vy += fy;
            nodes[j].vx -= fx;
            nodes[j].vy -= fy;
        }
    }

    // Spring forces (Hooke's law)
    for (var s = 0; s < springs.length; s++) {
        var nodeA = findNode(springs[s].a);
        var nodeB = findNode(springs[s].b);
        if (!nodeA || !nodeB) continue;
        var dx = nodeB.x - nodeA.x;
        var dy = nodeB.y - nodeA.y;
        var dist = Math.sqrt(dx * dx + dy * dy) || 1;
        var displacement = dist - springs[s].rest;
        var force = (springs[s].k || config.springCoeff) * displacement;
        nodeA.vx += (dx / dist) * force;
        nodeA.vy += (dy / dist) * force;
        nodeB.vx -= (dx / dist) * force;
        nodeB.vy -= (dy / dist) * force;
    }

    // Integration + damping + centering (per node)
    for (var n = 0; n < nodes.length; n++) {
        // Order: 4, 0, 2, 3, 5, 1  (from "4|0|2|3|5|1")
        nodes[n].vx += (400 - nodes[n].x) * config.centerGravity;   // case 4: center pull X
        nodes[n].vy += (300 - nodes[n].y) * config.centerGravity;   // case 0: center pull Y
        nodes[n].vx *= config.amplification;                         // case 2: damp X
        nodes[n].vy *= config.amplification;                         // case 3: damp Y
        nodes[n].x += nodes[n].vx;                                   // case 5: integrate X
        nodes[n].y += nodes[n].vy;                                   // case 1: integrate Y
    }
}

// Spawn a particle from a random node
function spawnParticle() {
    if (particles.length >= config.streamCount) return;
    var source = nodes[Math.floor(Math.random() * nodes.length)];
    var angle = Math.random() * TAU;
    var speed = 0.3 + Math.random() * SQRT_HALF;
    particles.push({
        x: source.x,
        y: source.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200,
        size: 0.8 + (Math.random() * PHI) * SQRT_HALF
    });
}

// Update particles
function updateParticles() {
    for (var i = particles.length - 1; i >= 0; i--) {
        // Order: 1, 0, 3, 4, 2, 6, 5  (from "1|0|3|4|2|6|5")
        var p = particles[i];                                        // case 1
        p.age++;                                                     // case 0
        p.vx *= (1 - config.streamDecay * 0.125);                   // case 3: drag X
        p.vy *= (1 - config.streamDecay * 0.125);                   // case 4: drag Y
        if (p.age > p.maxAge) particles.splice(i, 1);               // case 2: remove dead
        p.x += p.vx;                                                 // case 6: move X
        p.y += p.vy;                                                 // case 5: move Y
    }
}

// Smooth camera follow
function updateCamera() {
    camera.x += (cameraTarget.x - camera.x) * config.theta;
    camera.y += (cameraTarget.y - camera.y) * config.theta;
    camera.zoom += (cameraTarget.zoom - camera.zoom) * config.theta;
}

// Main loop
function tick() {
    simulate();
    updateParticles();
    updateCamera();
    if (frameCount % 3 === 0) spawnParticle();
    frameCount++;
}

setInterval(tick, 16); // ~60fps
```

## Verification: Do the Names Match the Operations?

| Name | Value | Actual Operation | Match? |
|---|---|---|---|
| `attractionForce` | 4000 | Used as **repulsion** numerator (`force / dist²`) — pushes nodes apart | ⚠️ **Mismatch** — acts as repulsion, not attraction |
| `springCoeff` | 0.004 | Default spring stiffness in Hooke's law (`k * displacement`) | ✅ Correct |
| `amplification` | 0.92 | Multiplied against velocity each frame — this is **damping** (`v *= 0.92`) | ⚠️ **Mismatch** — should be called "damping" |
| `centerGravity` | 0.0003 | Pulls nodes toward center point (400, 300) | ✅ Correct |
| `streamCount` | 40 | Max number of particles allowed | ✅ Correct |
| `streamDecay` | 0.04 | Slows particles over time (drag) | ✅ Correct |
| `theta` | 0.06 | Camera interpolation/smoothing factor (lerp coefficient) | ✅ Correct (θ as a generic parameter) |

### Summary

This is a **force-directed graph layout** with 6 nodes (Hub + 5 Greek-letter satellites), 8 spring connections, ambient particles, and a smooth-follow camera. Two config names are misleading:
- **`attractionForce`** actually computes **repulsion** (inverse-square pushing nodes apart)
- **`amplification`** actually performs **damping** (multiplying velocity by 0.92 shrinks it each frame)
